const now = new Date();
const yesterday = new Date(now - 24 * 60 * 60 * 1000);
return [{ json: { since: yesterday.toISOString(), until: now.toISOString() } }];

const orders = $input.first().json.orders || [];
const dateRange = $('Build Date Range').first().json;
const reportDate = new Date().toISOString().split('T')[0];

const totalOrders = orders.length;
const totalRevenue = orders.reduce((sum, o) => sum + parseFloat(o.total_price || 0), 0);
const avgOrderValue = totalOrders > 0 ? Math.round(totalRevenue / totalOrders * 100) / 100 : 0;

const paid = orders.filter(o => o.financial_status === 'paid').length;
const pending = orders.filter(o => o.financial_status === 'pending').length;
const refunded = orders.filter(o => o.financial_status === 'refunded').length;

const fulfilled = orders.filter(o => o.fulfillment_status === 'fulfilled').length;
const unfulfilled = orders.filter(o => !o.fulfillment_status || o.fulfillment_status === 'unfulfilled').length;

// Top products
const productCounts = {};
for (const order of orders) {
  for (const item of (order.line_items || [])) {
    productCounts[item.title] = (productCounts[item.title] || 0) + item.quantity;
  }
}
const topProducts = Object.entries(productCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, qty]) => `${name}: ${qty} sold`)
  .join('<br>');

const currency = orders[0]?.currency || 'USD';

return [{
  json: {
    report_date: reportDate,
    total_orders: totalOrders,
    total_revenue: Math.round(totalRevenue * 100) / 100,
    avg_order_value: avgOrderValue,
    currency,
    paid,
    pending,
    refunded,
    fulfilled,
    unfulfilled,
    top_products: topProducts || 'No orders'
  }
}];
